Here's a sample Java code that implements the above requirements:

import java.util.Scanner;

public class SmartInvestor {
    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);
        System.out.print("Please enter your account balance: ");
        double accountBalance = input.nextDouble();
        System.out.print("Please enter the investment amount: ");
        double investmentAmount = input.nextDouble();

        if (investmentAmount <= 0) {
            System.out.println("Invalid investment amount. Please enter a positive value.");
        } else {
            if (investmentAmount <= 0.1 * accountBalance) {
                System.out.println("This investment is safe.");
            } else {
                System.out.println("WARNING: This investment is risky as it is more than 10% of your account balance.");
            }

            System.out.print("Do you want to proceed with this investment? (y/n)");
            String proceed = input.next().trim().toLowerCase();
            if (proceed.equals("y")) {
                System.out.println("Thank you for your investment. Good luck!");
            } else {
                System.out.println("Thank you for using the program.");
            }
        }
    }
}
